const modes={systems:{number:'01 / SYSTEMS',title:'Lumi / Hermes',copy:'A continuity system for working with AI without losing the thread—or the person.',color:'#f3bd39'},products:{number:'02 / PRODUCTS',title:'WeTheAIs',copy:'A public place to think about how people and AI might make better things together.',color:'#ef7450'},people:{number:'03 / PEOPLE',title:'Equa',copy:'A small experiment in making the logic behind a decision visible, adjustable, and discussable.',color:'#9dbe88'}};
const feature=document.querySelector('#feature');
document.querySelectorAll('[data-mode]').forEach((button)=>button.addEventListener('click',()=>{document.querySelectorAll('[data-mode]').forEach((item)=>item.setAttribute('aria-pressed',String(item===button)));const mode=modes[button.dataset.mode];feature.querySelector('.feature-number').textContent=mode.number;feature.querySelector('h3').textContent=mode.title;feature.querySelector('.feature-copy').textContent=mode.copy;feature.style.background=mode.color;}));
const toast=document.querySelector('#toast');let toastTimer;function showToast(message){toast.textContent=message;toast.hidden=false;clearTimeout(toastTimer);toastTimer=setTimeout(()=>{toast.hidden=true},3200)}
document.querySelector('#pencil').addEventListener('click',()=>showToast('Margin note: years in labor-union communications taught Billy that clarity is a form of respect.'));
document.querySelectorAll('[data-project]').forEach((button)=>button.addEventListener('click',()=>showToast(`${button.dataset.project}: selected for the shelf. A fuller story can live here in the chosen direction.`)));
